using System.ComponentModel;
using System.Text;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides a note-taking tool that the agent uses to record research findings.
/// Notes are stored in memory and can be retrieved for summarization.
/// </summary>
public sealed class NoteTool
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes.AsReadOnly();

    [Description("Saves a research note with a title and content. Use this to record key findings from web searches.")]
    public string SaveNote(
        [Description("A short title for the note")] string title,
        [Description("The content of the note — key facts, data points, or insights")] string content,
        [Description("The source URL where this information was found")] string sourceUrl)
    {
        var note = new Note(title, content, sourceUrl, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieves all saved research notes. Use this to review findings before writing a summary.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"[{i + 1}] {note.Title}");
            sb.AppendLine($"    Source: {note.SourceUrl}");
            sb.AppendLine($"    {note.Content}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

public sealed record Note(string Title, string Content, string SourceUrl, DateTime SavedAt);

