using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using OpenAI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Read configuration — API key must come from environment or user-secrets, never hardcoded
var openAiApiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OpenAI API key via 'AI:ApiKey' in config, or the OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

// Optional: Brave Search API key for real web search (falls back to simulated results)
var braveApiKey = builder.Configuration["Search:BraveApiKey"]
    ?? Environment.GetEnvironmentVariable("BRAVE_API_KEY");

// Register HttpClient and tools
builder.Services.AddHttpClient();
builder.Services.AddSingleton(sp =>
    new WebSearchTool(sp.GetRequiredService<IHttpClientFactory>().CreateClient("search"), braveApiKey));
builder.Services.AddSingleton<NoteTool>();

// Register IChatClient through MEAI abstraction
builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(openAiApiKey)));

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var webSearch = host.Services.GetRequiredService<WebSearchTool>();
var noteTool = host.Services.GetRequiredService<NoteTool>();

// Build AI functions from the tool instances
var tools = new AIFunctionFactory.Builder()
    .FromInstance(webSearch)
    .FromInstance(noteTool)
    .Build();

// Create the agent with tool access
var agent = new ChatClientAgent(chatClient, tools)
{
    Name = "ResearchAgent",
    Instructions = """
        You are a research assistant. Your job is to thoroughly research a topic using web search,
        take structured notes on your findings, and then produce a clear summary.

        Follow this workflow:
        1. Search the web for the topic using multiple queries to cover different angles.
        2. For each useful result, save a note with the key facts, insights, and the source URL.
        3. After gathering enough information (at least 3-5 notes), retrieve all your notes.
        4. Write a comprehensive summary that synthesizes your findings, organized by theme.
        5. Include source citations at the end.

        Be thorough but concise. Focus on factual, well-sourced information.
        """,
};

// Get the research topic
Console.ForegroundColor = ConsoleColor.Cyan;
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent               ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.ResetColor();
Console.WriteLine();

string topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a topic to research: ");
    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
}

Console.WriteLine();
Console.ForegroundColor = ConsoleColor.Yellow;
Console.WriteLine($"Researching: {topic}");
Console.WriteLine("This may take a moment...\n");
Console.ResetColor();

// Run the agent with iteration limits and streaming
var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();
Console.WriteLine();

// Display saved notes summary
Console.ForegroundColor = ConsoleColor.Green;
Console.WriteLine($"Research complete — {noteTool.Notes.Count} notes collected from {noteTool.Notes.Select(n => n.SourceUrl).Distinct().Count()} sources.");
Console.ResetColor();

